mapper.select:
select * from (select i.*, j.DEVICE_IP as NODE_IP, j.PORT as NODE_PORT, NULL INSTANCE_ID, NULL INSTANCE_TYPE, NULL DB_TYPE, j.create_user from SYS_MESSAGE i inner join T_DEVICE j on i.object_id = j.id where i.table_name = 't_device' )
AND (RESOURCE_NAME LIKE concat('%', #{param.searchValue}, '%') OR CONTENT LIKE concat('%', #{param.searchValue}, '%'))
AND CREATE_TIME > #{time}
AND MSG_LEVEL = #{param.alarmLevel}
order by FIELD(ACTIVE_STATE, 'live', 'death'), create_time desc

SELECT * from ( SELECT i.*, j.DEVICE_IP as NODE_IP, j.PORT as NODE_PORT, NULL INSTANCE_ID, NULL INSTANCE_NAME FROM SYS_MESSAGE i, T_DEVICE j WHERE i.object_id = j.id ) WHERE 1 = 1
and active_state = #{param.activeState}
and create_time >= #{queryTime}
order by create_time desc
